package emit

import (
	"fmt"
	"io"
	"sort"
	"strings"

	"github.com/hstern/go-ocsf/internal/gen/schema"
)

// writeObjectFile renders one OCSF object as a Go source file.
// Output shape (post-go/format):
//
//	// Code generated by internal/gen; DO NOT EDIT.
//	// Copyright 2026 The go-ocsf Authors
//	// SPDX-License-Identifier: Apache-2.0
//
//	package objects
//
//	import "encoding/json"  // omitted when not needed
//
//	// User describes the user object ...
//	type User struct {
//	    // Name is the username...
//	    Name string `json:"name,omitempty"`
//	    ...
//	}
//
// Pure structs only — methods (ClassUID, Validate) are not
// emitted for objects in this phase. Phase 4 (Validate) and
// Phase 3 (Event.ClassUID equivalent) cover those for the
// classes that need them.
func writeObjectFile(w io.Writer, s *schema.Schema, obj schema.ObjectClass) error {
	if err := writeFileHeader(w, "objects"); err != nil {
		return err
	}
	// Discover imports from attribute types. Sorted + deduped for
	// determinism. The std-library set is tiny so we don't worry
	// about grouping; one import block, sorted, is enough.
	imports := map[string]bool{}
	for _, a := range obj.Attributes { //nolint:gocritic // copy fine in codegen path
		for _, imp := range fieldImports(a) {
			imports[imp] = true
		}
	}
	if len(imports) > 0 {
		impPaths := make([]string, 0, len(imports))
		for p := range imports {
			impPaths = append(impPaths, p)
		}
		sort.Strings(impPaths)
		if _, err := fmt.Fprintln(w, "import ("); err != nil {
			return err
		}
		for _, p := range impPaths {
			if _, err := fmt.Fprintf(w, "\t%q\n", p); err != nil {
				return err
			}
		}
		if _, err := fmt.Fprintln(w, ")"); err != nil {
			return err
		}
		if _, err := fmt.Fprintln(w); err != nil {
			return err
		}
	}

	typeName := goName(obj.Name)
	if err := writeObjectGodoc(w, obj, typeName); err != nil {
		return err
	}
	if _, err := fmt.Fprintf(w, "type %s struct {\n", typeName); err != nil {
		return err
	}
	for i, a := range obj.Attributes { //nolint:gocritic // copy fine in codegen path
		if i > 0 {
			if _, err := fmt.Fprintln(w); err != nil {
				return err
			}
		}
		if err := writeField(w, s, a); err != nil {
			return fmt.Errorf("attribute %q: %w", a.Name, err)
		}
	}
	if _, err := fmt.Fprintln(w, "}"); err != nil {
		return err
	}
	return nil
}

// writeObjectGodoc emits the godoc paragraph that precedes the
// struct declaration. The text reproduces the schema's caption
// and description; the SchemaName comment surfaces the upstream
// snake_case name verbatim so a developer searching the codebase
// for the OCSF identifier finds the Go type.
func writeObjectGodoc(w io.Writer, obj schema.ObjectClass, typeName string) error {
	desc := strings.TrimSpace(obj.Description)
	if desc == "" {
		desc = obj.Caption
	}
	if desc == "" {
		desc = "is an OCSF " + obj.Name + " object."
	} else {
		desc = "describes the OCSF " + obj.Caption + " object: " + desc
	}
	lines := wrapAndStripHTML(typeName+" "+desc, 70)
	for _, l := range lines {
		if _, err := fmt.Fprintf(w, "// %s\n", l); err != nil {
			return err
		}
	}
	if _, err := fmt.Fprintf(w, "//\n// OCSF name: %s.\n", obj.Name); err != nil {
		return err
	}
	if obj.Deprecated != nil {
		if _, err := fmt.Fprintf(w, "//\n// Deprecated: %s\n", obj.Deprecated.Message); err != nil {
			return err
		}
	}
	return nil
}

// writeField emits one struct-field declaration with its godoc.
// The godoc carries the OCSF attribute caption and description
// (HTML-stripped, wrapped) plus a marker line citing the upstream
// snake_case attribute name and OCSF type for provenance.
func writeField(w io.Writer, s *schema.Schema, a schema.ClassAttr) error {
	typ, err := fieldGoType(s, a)
	if err != nil {
		return err
	}
	caption := strings.TrimSpace(a.Caption)
	desc := strings.TrimSpace(a.Description)
	fieldName := goFieldName(a.Name)
	var docLead string
	if caption != "" {
		docLead = fieldName + " is the " + caption + "."
	} else {
		docLead = fieldName + " is the " + a.Name + " attribute."
	}
	if desc != "" {
		docLead += " " + desc
	}
	lines := wrapAndStripHTML(docLead, 70)
	for _, l := range lines {
		if _, err := fmt.Fprintf(w, "\t// %s\n", l); err != nil {
			return err
		}
	}
	// Provenance footer: OCSF attribute name, dictionary type,
	// and requirement.
	provenance := fmt.Sprintf("OCSF: %s (type %s, requirement %s)", a.Name, ocsfTypeText(a), reqText(a.Requirement))
	if _, err := fmt.Fprintf(w, "\t//\n\t// %s\n", provenance); err != nil {
		return err
	}
	if a.Deprecated != nil {
		if _, err := fmt.Fprintf(w, "\t//\n\t// Deprecated: %s\n", a.Deprecated.Message); err != nil {
			return err
		}
	}
	tag := jsonTagOpts(a)
	if _, err := fmt.Fprintf(w, "\t%s %s `json:%q`\n", fieldName, typ, tag); err != nil {
		return err
	}
	return nil
}

// reqText normalizes a possibly-empty Requirement to its string
// form. "optional" is the safe default for missing requirement
// metadata.
func reqText(req string) string {
	if req == "" {
		return "optional"
	}
	return req
}

// ocsfTypeText formats an attribute's OCSF type for inclusion in
// the provenance comment. Arrays are rendered as `[]T` so the
// comment matches the wire shape.
func ocsfTypeText(a schema.ClassAttr) string {
	if a.Type == "" {
		return "unknown"
	}
	if a.IsArray {
		return "[]" + a.Type
	}
	return a.Type
}

// wrapAndStripHTML turns a paragraph of OCSF-style mixed prose
// and HTML into a sequence of godoc-ready lines no wider than
// width runes. The cleanup is intentionally simple: HTML tags
// are stripped (everything inside angle brackets removed),
// runs of whitespace collapse to a single space, then the
// result is greedy-wrapped at word boundaries.
//
// The simplification loses formatting nuance (lists become
// run-on sentences) but produces readable godoc that survives
// godoc rendering. The full schema text is the source of truth;
// the godoc paragraph is a navigation aid, not a replacement.
func wrapAndStripHTML(s string, width int) []string {
	cleaned := stripHTML(s)
	cleaned = collapseSpaces(cleaned)
	cleaned = strings.TrimSpace(cleaned)
	if cleaned == "" {
		return nil
	}
	words := strings.Fields(cleaned)
	if len(words) == 0 {
		return nil
	}
	var lines []string
	var cur strings.Builder
	cur.WriteString(words[0])
	for _, w := range words[1:] {
		if cur.Len()+1+len(w) > width {
			lines = append(lines, cur.String())
			cur.Reset()
			cur.WriteString(w)
			continue
		}
		cur.WriteByte(' ')
		cur.WriteString(w)
	}
	if cur.Len() > 0 {
		lines = append(lines, cur.String())
	}
	return lines
}

// stripHTML removes everything between < and > (inclusive). Not
// HTML-aware (no entity decoding, no attribute handling) — the
// schema doesn't use entities in tags it places, and the simple
// regex-free implementation keeps the codegen tool dependency-
// free.
func stripHTML(s string) string {
	var b strings.Builder
	inTag := false
	for _, r := range s {
		switch {
		case r == '<':
			inTag = true
		case r == '>':
			inTag = false
		case !inTag:
			b.WriteRune(r)
		}
	}
	return b.String()
}

// collapseSpaces replaces any run of whitespace with a single
// ASCII space.
func collapseSpaces(s string) string {
	var b strings.Builder
	prevSpace := false
	for _, r := range s {
		if r == ' ' || r == '\t' || r == '\n' || r == '\r' {
			if !prevSpace {
				b.WriteByte(' ')
				prevSpace = true
			}
			continue
		}
		prevSpace = false
		b.WriteRune(r)
	}
	return b.String()
}
